function countEqualRowColumnPairs(grid) {
    let n = grid.length;
    let ans = 0;

    for (let i = 0; i < n; ++i) {
        for (let j = 0; j < n; ++j) {
            let equal = true;
            for (let k = 0; k < n; ++k) {
                if (grid[i][k] !== grid[k][j]) {
                    equal = false;
                    break;
                }
            }
            if (equal) {
                ++ans;
            }
        }
    }

    return ans;
}
```

